@Component
class AuthSessionStore {
    static final String COOKIE_NAME = "SPSESSION";
    private static final String HMAC_ALG = "HmacSHA256";

    private final Map<String, AuthSession> sessions = new ConcurrentHashMap<>();

    private final byte[] secret = "CHANGE_ME_TO_A_LONG_RANDOM_SECRET_FROM_CONFIG".getBytes(StandardCharsets.UTF_8);
    private final long ttlSeconds = 3600;

    public long getTtlSeconds() {
        return ttlSeconds;
    }

    public AuthSession createSession(SamlPrincipal principal) {
        String id = UUID.randomUUID().toString();
        long now = System.currentTimeMillis();
        long expiresAt = now + ttlSeconds * 1000L;

        if (principal.getNotOnOrAfterEpochSeconds() != null) {
            long noaMs = principal.getNotOnOrAfterEpochSeconds() * 1000L;
            expiresAt = Math.min(expiresAt, noaMs);
        }

        AuthSession session = new AuthSession(id, principal, expiresAt);
        sessions.put(id, session);
        return session;
    }

    public AuthSession getBySignedSessionId(String signed) {
        String id = verifyAndExtractSessionId(signed);
        if (id == null) return null;
        AuthSession s = sessions.get(id);
        if (s == null) return null;
        if (s.isExpired()) {
            sessions.remove(id);
            return null;
        }
        return s;
    }

    public void deleteBySignedSessionId(String signed) {
        String id = verifyAndExtractSessionId(signed);
        if (id != null) sessions.remove(id);
    }

    public String signSessionId(String sessionId) {
        String sig = base64Url(hmac(sessionId.getBytes(StandardCharsets.UTF_8)));
        return sessionId + "." + sig;
    }

    private String verifyAndExtractSessionId(String signed) {
        int idx = signed.lastIndexOf('.');
        if (idx <= 0) return null;
        String id = signed.substring(0, idx);
        String sig = signed.substring(idx + 1);

        byte[] expected = hmac(id.getBytes(StandardCharsets.UTF_8));
        byte[] provided;
        try {
            provided = base64UrlDecode(sig);
        } catch (Exception e) {
            return null;
        }
        if (!MessageDigest.isEqual(expected, provided)) return null;
        return id;
    }

    private byte[] hmac(byte[] data) {
        try {
            Mac mac = Mac.getInstance(HMAC_ALG);
            mac.init(new SecretKeySpec(secret, HMAC_ALG));
            return mac.doFinal(data);
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }

    private static String base64Url(byte[] bytes) {
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private static byte[] base64UrlDecode(String s) {
        return Base64.getUrlDecoder().decode(s);
    }
}

